   265→async function handleRefreshTokenGrant(
   266→  ctx: Router.RouterContext,
   267→  { config, stateStore, clientId, body }: GrantHandlerDeps
   268→) {
   269→  const refreshToken = body['refresh_token'];
   270→
   271→  const validationError = validateRefreshTokenRequest({ refreshToken, clientId });
   272→  if (validationError) {
   273→    ctx.logger.warn({ error: validationError.body.error, description: validationError.body.error_description, clientId }, 'Refresh token request validation failed');
   274→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   275→    ctx.status = validationError.status;
   276→    ctx.body = validationError.body;
   277→    return;
   278→  }
   279→
   280→  // Look up the grant by refresh token
   281→  let grant: AuthorizationGrantRecord | null;
   282→  try {
   283→    grant = await stateStore.getAuthorizationGrantByRefreshToken(refreshToken!);
   284→  } catch (err) {
   285→    ctx.logger.error({ error: err instanceof Error ? err.message : String(err), clientId }, 'Failed to look up refresh token');
   286→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   287→    ctx.status = 500;
   288→    ctx.body = { error: 'server_error', error_description: 'Failed to look up refresh token' };
   289→    return;
   290→  }
   291→
   292→  if (!grant) {
   293→    ctx.logger.warn({ clientId, refreshToken: refreshToken ? `${refreshToken.substring(0, 8)}...` : undefined }, 'Refresh token not found or expired');
   294→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   295→    ctx.status = 400;
   296→    ctx.body = { error: 'invalid_grant', error_description: 'Invalid or expired refresh token' };
   297→    return;
   298→  }
   299→
   300→  // Verify the client matches
   301→  if (grant.clientId !== clientId) {
   302→    ctx.logger.warn({ clientId, grantClientId: grant.clientId }, 'Refresh token belongs to different client');
   303→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   304→    ctx.status = 400;
   305→    ctx.body = { error: 'invalid_grant', error_description: 'Refresh token was issued to a different client' };
   306→    return;
   307→  }
   308→
   309→  // Get fresh Mittwald tokens
   310→  let mittwaldTokens;
   311→
   312→  // Try to use Mittwald's refresh token if available
   313→  if (grant.mittwaldTokens?.refresh_token) {
   314→    try {
   315→      mittwaldTokens = await refreshMittwaldTokens({
   316→        config,
   317→        refreshToken: grant.mittwaldTokens.refresh_token,
   318→        logger: ctx.logger
   319→      });
   320→      ctx.logger.debug({ clientId }, 'Refreshed Mittwald tokens successfully');
   321→    } catch (err) {
   322→      ctx.logger.warn({
   323→        error: err instanceof Error ? err.message : String(err),
   324→        clientId
   325→      }, 'Failed to refresh Mittwald tokens, using cached tokens');
   326→      // Fall back to cached tokens if refresh fails
   327→      mittwaldTokens = grant.mittwaldTokens;
   328→    }
   329→  } else {
   330→    // No Mittwald refresh token available, use cached tokens
   331→    ctx.logger.debug({ clientId }, 'No Mittwald refresh token, using cached tokens');
   332→    mittwaldTokens = grant.mittwaldTokens;
   333→  }
   334→
   335→  if (!mittwaldTokens) {
   336→    ctx.logger.error({ clientId }, 'No Mittwald tokens available for refresh');
   337→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   338→    ctx.status = 400;
   339→    ctx.body = { error: 'invalid_grant', error_description: 'Session expired, please re-authenticate' };
   340→    return;
   341→  }
   342→
   343→  // Issue new bridge tokens
   344→  let bridgeTokens;
   345→  try {
   346→    bridgeTokens = await issueBridgeTokens({ config, grant, mittwaldTokens });
   347→  } catch (err) {
   348→    ctx.logger.error({ error: err instanceof Error ? err.message : String(err), clientId }, 'Failed to issue bridge tokens');
   349→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   350→    ctx.status = 500;
   351→    ctx.body = { error: 'server_error', error_description: 'Failed to issue bridge tokens' };
   352→    return;
   353→  }
   354→
   355→  // Update the grant with new tokens (rotate refresh token)
   356→  const updatedGrant = {
   357→    ...grant,
   358→    mittwaldTokens,
   359→    refreshToken: bridgeTokens.refreshToken,
   360→    refreshTokenExpiresAt: bridgeTokens.refreshTokenExpiresAt
   361→  };
   362→  try {
   363→    await stateStore.updateAuthorizationGrant(updatedGrant);
   364→  } catch (err) {
   365→    ctx.logger.error({ error: err instanceof Error ? err.message : String(err), clientId }, 'Failed to update grant after refresh');
   366→    tokenRequests.inc({ grant_type: 'refresh_token', status: 'error' });
   367→    ctx.status = 500;
   368→    ctx.body = { error: 'server_error', error_description: 'Failed to persist refreshed tokens' };
   369→    return;
   370→  }
   371→
   372→  ctx.logger.info({ clientId, scope: grant.scope }, 'Bridge tokens issued via refresh_token');
   373→
   374→  tokenRequests.inc({ grant_type: 'refresh_token', status: 'success' });
   375→  ctx.status = 200;
   376→  ctx.body = {
   377→    access_token: bridgeTokens.accessToken,
   378→    token_type: 'Bearer',
   379→    expires_in: config.bridge.accessTokenTtlSeconds,
   380→    scope: grant.scope,
   381→    refresh_token: bridgeTokens.refreshToken
   382→  };
   383→}
   384→
   385→interface ClientAuthError {
   386→  status: number;
   387→  body: Record<string, string>;
   388→  wwwAuthenticate?: string;
   389→}
   390→
   391→function validateAuthorizationCodeRequest(input: {
   392→  code?: string;
   393→  redirectUri?: string;
   394→  clientId?: string;
   395→  codeVerifier?: string;
   396→}): { status: number; body: Record<string, string> } | null {
   397→  if (!input.code) {
   398→    return { status: 400, body: { error: 'invalid_request', error_description: 'code is required' } };
   399→  }
   400→
   401→  if (!input.redirectUri) {
   402→    return { status: 400, body: { error: 'invalid_request', error_description: 'redirect_uri is required' } };
   403→  }
   404→
   405→  if (!input.clientId) {
   406→    return { status: 400, body: { error: 'invalid_request', error_description: 'client_id is required' } };
   407→  }
   408→
   409→  if (!input.codeVerifier) {
   410→    return { status: 400, body: { error: 'invalid_request', error_description: 'code_verifier is required' } };
   411→  }
   412→
   413→  return null;
   414→}
   415→
   416→function validateRefreshTokenRequest(input: {
   417→  refreshToken?: string;
   418→  clientId?: string;
   419→}): { status: number; body: Record<string, string> } | null {
   420→  if (!input.refreshToken) {
   421→    return { status: 400, body: { error: 'invalid_request', error_description: 'refresh_token is required' } };
   422→  }
   423→
   424→  if (!input.clientId) {
   425→    return { status: 400, body: { error: 'invalid_request', error_description: 'client_id is required' } };
   426→  }
   427→
   428→  return null;
   429→}
   430→
   431→function validateClientCredentials(input: {
   432→  registration: ClientRegistrationRecord;
   433→  authorizationHeader?: string;
   434→  clientId: string;
   435→  clientSecretFromBody?: string;
   436→}): ClientAuthError | null {
   437→  const { registration, authorizationHeader, clientId, clientSecretFromBody } = input;
   438→
   439→  switch (registration.tokenEndpointAuthMethod) {
   440→    case 'none':
   441→      return null;
   442→    case 'client_secret_post': {
   443→      if (!registration.clientSecret) {
   444→        return {
   445→          status: 500,
   446→          body: { error: 'server_error', error_description: 'Client secret not available' }
   447→        };
   448→      }
   449→      if (!clientSecretFromBody) {
   450→        return {
   451→          status: 401,
   452→          body: { error: 'invalid_client', error_description: 'client_secret is required' },
   453→          wwwAuthenticate: 'Basic realm="OAuth Bridge"'
   454→        };
   455→      }
   456→      if (clientSecretFromBody !== registration.clientSecret) {
   457→        return {
