     1→#!/usr/bin/env node
     2→/**
     3→ * @file Main entry point for the MCP server
     4→ * @module index
     5→ * 
     6→ * @remarks
     7→ * This is the executable entry point for the MCP server when run directly.
     8→ * It loads environment variables and starts the HTTP server on the configured port.
     9→ * 
    10→ * The server can be started using:
    11→ * - `npm start` - Production mode
    12→ * - `npm run dev` - Development mode with auto-reload
    13→ * - `node dist/index.js` - Direct execution
    14→ * 
    15→ * Required environment variables:
    16→ * - JWT_SECRET: Secret for signing JWT tokens
    17→ * 
    18→ * @see {@link https://modelcontextprotocol.io} Model Context Protocol Documentation
    19→ */
    20→
    21→import dotenv from 'dotenv';
    22→dotenv.config();
    23→
    24→import { startServer, markServerShuttingDown } from './server.js';
    25→import { CONFIG, validateConfig } from './server/config.js';
    26→import { redisClient } from './utils/redis-client.js';
    27→import { logger } from './utils/logger.js';
    28→import { getMCPHandlerInstance } from './server/mcp.js';
    29→import { runStartupValidation } from './server/startup-validator.js';
    30→
    31→// Run security validation first - blocks startup in production with placeholder secrets or wildcard CORS
    32→runStartupValidation();
    33→
    34→// Validate configuration and warn about missing .env
    35→try {
    36→  validateConfig();
    37→} catch (error) {
    38→  console.warn('Configuration Warning:', error instanceof Error ? error.message : String(error));
    39→  console.warn('Make sure you have a .env file with required environment variables:');
    40→  console.warn('   - JWT_SECRET=your_jwt_secret');
    41→  console.warn('See .env.example for a template');
    42→  console.warn('Server will start but API calls may fail without proper configuration\n');
    43→}
    44→
    45→// Start the server
    46→const port = parseInt(CONFIG.PORT, 10);
    47→(async () => {
    48→  try {
    49→    const server = await startServer(port);
    50→
    51→    server.on('error', (error) => {
    52→      logger.error('Failed to start server:', error);
    53→      process.exit(1);
    54→    });
    55→
    56→    let gracefulShutdownInitiated = false;
    57→
    58→    const gracefulShutdown = async (signal: NodeJS.Signals): Promise<void> => {
    59→      if (gracefulShutdownInitiated) {
    60→        logger.warn(`Shutdown already in progress, ignoring ${signal}`);
    61→        return;
    62→      }
    63→
    64→      gracefulShutdownInitiated = true;
    65→      markServerShuttingDown();
    66→      logger.info(`${signal} received, starting graceful shutdown...`);
    67→
    68→      const forceExitTimer = setTimeout(() => {
    69→        logger.warn('Graceful shutdown timeout reached, forcing exit');
    70→        process.exit(0);
    71→      }, 25000);
    72→      forceExitTimer.unref();
    73→
    74→      await new Promise<void>((resolve) => {
    75→        server.close((error?: Error) => {
    76→          if (error) {
    77→            logger.error('Error closing HTTP server during shutdown', error);
    78→          } else {
    79→            logger.info('HTTP server closed');
    80→          }
    81→          resolve();
    82→        });
    83→      });
    84→
    85→      try {
    86→        const handler = getMCPHandlerInstance();
    87→        handler?.shutdown();
    88→      } catch (error) {
    89→        logger.error('Error shutting down MCP handler', error);
    90→      }
    91→
    92→      try {
    93→        await redisClient.disconnect();
    94→      } catch (error) {
    95→        logger.error('Error closing Redis connection during shutdown', error);
    96→      }
    97→
    98→      clearTimeout(forceExitTimer);
    99→      logger.info('Graceful shutdown complete');
   100→      process.exit(0);
   101→    };
   102→
